mapper.select:
select t1.database_type, t1.schema_name, t1.database_name,t1.name as databaseConnectName, t.*
from metadata_table_info t
inner join metadata_datasource_info t1 on t1.id = t.datasource_id



            and t.datasource_id = #{query.datasourceId}



            and t1.schema_name like concat('%', #{query.schemaName}, '%')



            and t1.name like concat('%', #{query.databaseConnectName}, '%')



            and t1.database_name like concat('%', #{query.databaseName}, '%')



            and t.table_name like concat('%', #{query.tableName}, '%')



            and t.table_desc like concat('%', #{query.tableDesc}, '%')



            and t.is_modify = #{query.isModify}



            and t.is_view = #{query.isView}



            and t.is_equal = #{query.isEqual}




order by t.create_time desc

select t1.database_type as databaseType, t1.name as datasourceName, t1.database_name as databaseName, t1.schema_name as schemaName, t.table_name as tableName, t2.column_name as columnName, t2.column_type as columnType, t2.java_type as columnJavaType, t.datasource_id as datasourceId from metadata_table_info t join metadata_datasource_info t1 on t1.id = t.datasource_id join metadata_column_info t2 on t.id = t2.table_id where t.datasource_id = #{datasourceId}
and t.table_name in #{name}
order by t.table_name,t2.column_serial asc

select t1.database_type, t1.schema_name, t1.database_name,t1.name as databaseConnectName, t.*
from metadata_table_info t
inner join metadata_datasource_info t1 on t1.id = t.datasource_id



            and t.datasource_id = #{query.option.datasourceId}



            and t1.schema_name like concat('%', #{query.option.schemaName}, '%')



            and t1.name like concat('%', #{query.option.databaseConnectName}, '%')



            and t1.database_name like concat('%', #{query.option.databaseName}, '%')



            and t.table_name like concat('%', #{query.option.tableName}, '%')



            and t.table_desc like concat('%', #{query.option.tableDesc}, '%')



            and t.is_modify = #{query.option.isModify}



            and t.is_view = #{query.option.isView}



            and t.is_equal = #{query.option.isEqual}




order by t.create_time desc
limit #{query.size} offset #{query.offset}

select count(0)
from metadata_table_info t
inner join metadata_datasource_info t1 on t1.id = t.datasource_id



            and t.datasource_id = #{query.option.datasourceId}



            and t1.schema_name like concat('%', #{query.option.schemaName}, '%')



            and t1.name like concat('%', #{query.option.databaseConnectName}, '%')



            and t1.database_name like concat('%', #{query.option.databaseName}, '%')



            and t.table_name like concat('%', #{query.option.tableName}, '%')



            and t.table_desc like concat('%', #{query.option.tableDesc}, '%')



            and t.is_modify = #{query.option.isModify}



            and t.is_view = #{query.option.isView}



            and t.is_equal = #{query.option.isEqual}

select count(1)
from metadata_table_info t


        and t.datasource_id = #{datasourceId}
